class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: Environment.GetEnvironmentVariable returns null
        // for empty values on Linux (previously returned ""). Use
        // a direct check via environment variable existence to distinguish
        // "not set" from "explicitly empty".
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val == null && !IsEnvironmentVariableDefined("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }

    private static bool IsEnvironmentVariableDefined(string variable)
    {
        // IDictionary contains all defined env vars, including those set to ""
        return Environment.GetEnvironmentVariables().Contains(variable);
    }
}

